:5:\\\"title\\\";s:52:\\\"Youth Corps Member (Web Designer) at GeekHub Nigeria\\\";s:12:\\\"company_name\\\";s:15:\\\"GeekHub Nigeria\\\";s:12:\\\"company_logo\\\";s:58:\\\"storage\\/logos\\/zyMoTL9czEE42EdjlcJXXWropgcFLqFKGbCUAGIx.png\\\";s:11:\\\"category_id\\\";i:1;s:8:\\\"job_type\\\";s:9:\\\"full-time\\\";s:8:\\\"location\\\";s:14:\\\"Abuja, Nigeria\\\";s:16:\\\"experience_level\\\";s:5:\\\"entry\\\";s:12:\\\"salary_range\\\";N;s:17:\\\"short_description\\\";s:1944:\\\"<p><strong>Job Summary<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>We are seeking young, vibrant, result driven Youth Corp Members to serve with us,as their place of primary assignment.<\\/li>\\r\\n\\t<li>We are looking for NYSC members to fill the position of:<\\/li>\\r\\n\\t<li>Web Designer: The Web Designer will be responsible for creating visually appealing and user-friendly websites, ensuring proper functionality, and implementing design principles to enhance the user experience.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>Desired Skills and Attributes<\\/strong><br \\/>\\r\\nWeb Designer:<\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Proven experience as a Web Developer, demonstrating proficiency in HTML, CSS, JavaScript, and other web technologies.<\\/li>\\r\\n\\t<li>Strong understanding of responsive web design, cross-browser compatibility, and web accessibility standards.<\\/li>\\r\\n\\t<li>Experience with front-end frameworks\\/libraries (e.g., Bootstrap, React, Vue.js) and back-end languages\\/frameworks (e.g., PHP, Python, Node.js) is preferred.<\\/li>\\r\\n\\t<li>Proficiency in version control systems (e.g., Git) and web development tools (e.g., IDEs, Code Igniter, Laravel, package managers) is a plus.<\\/li>\\r\\n\\t<li>Strong Back end integration frameworks and database management using technologies like MYSQL, PHP<\\/li>\\r\\n\\t<li>Attention to detail<\\/li>\\r\\n\\t<li>Understanding of user experience (UX) principles<\\/li>\\r\\n\\t<li>Proficient in use of AI vibe coding to create Websites landing pages and applications<\\/li>\\r\\n\\t<li>Proficient in the use of LLMs like ChatGPT, Google Gemini, etc<\\/li>\\r\\n\\t<li>Ability to work with design software (e.g., Figma, Adobe Photoshop, Illustrator), problem-solving skills<\\/li>\\r\\n\\t<li>Time management skills.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>Method of Application&nbsp;<\\/strong><\\/p>\\r\\n\\r\\n<p>Interested and qualified candidates should send their CV to:&nbsp;<strong><a href=\\\"mailto:Corpers@geekhub.com.ng\\\">Corpers@geekhub.com.ng<\\/a>&nbsp;&nbsp;<\\/strong>using the Job title as the subject of the mail.<\\/p>\\r\\n\\r\\n<p>&nbsp;<\\/p>\\\";s:9:\\\"apply_url\\\";s:76:\\\"https:\\/\\/www.myjobmag.com\\/job\\/youth-corps-member-web-designer-geekhub-nigeria\\\";s:8:\\\"deadline\\\";N;s:11:\\\"is_featured\\\";i:0;s:6:\\\"status\\\";s:6:\\\"active\\\";s:6:\\\"source\\\";s:8:\\\"MyJobMag\\\";s:10:\\\"created_at\\\";s:19:\\\"2026-02-11 19:00:23\\\";s:10:\\\"updated_at\\\";s:19:\\\"2026-02-11 19:00:23\\\";s:9:\\\"is_remote\\\";i:0;}s:11:\\\"\\u0000*\\u0000original\\\";a:18:{s:2:\\\"id\\\";i:10;s:5:\\\"title\\\";s:52:\\\"Youth Corps Member (Web Designer) at GeekHub Nigeria\\\";s:12:\\\"company_name\\\";s:15:\\\"GeekHub Nigeria\\\";s:12:\\\"company_logo\\\";s:58:\\\"storage\\/logos\\/zyMoTL9czEE42EdjlcJXXWropgcFLqFKGbCUAGIx.png\\\";s:11:\\\"category_id\\\";i:1;s:8:\\\"job_type\\\";s:9:\\\"full-time\\\";s:8:\\\"location\\\";s:14:\\\"Abuja, Nigeria\\\";s:16:\\\"experience_level\\\";s:5:\\\"entry\\\";s:12:\\\"salary_range\\\";N;s:17:\\\"short_description\\\";s:1944:\\\"<p><strong>Job Summary<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>We are seeking young, vibrant, result driven Youth Corp Members to serve with us,as their place of primary assignment.<\\/li>\\r\\n\\t<li>We are looking for NYSC members to fill the position of:<\\/li>\\r\\n\\t<li>Web Designer: The Web Designer will be responsible for creating visually appealing and user-friendly websites, ensuring proper functionality, and im