(14, '15f8dadc-b0e3-482d-ac4b-ca1ff92be9a4', 'database', 'default', '{\"uuid\":\"15f8dadc-b0e3-482d-ac4b-ca1ff92be9a4\",\"displayName\":\"App\\\\Mail\\\\JobAlertMail\",\"job\":\"Illuminate\\\\Queue\\\\CallQueuedHandler@call\",\"maxTries\":null,\"maxExceptions\":null,\"failOnTimeout\":false,\"backoff\":null,\"timeout\":null,\"retryUntil\":null,\"data\":{\"commandName\":\"Illuminate\\\\Mail\\\\SendQueuedMailable\",\"command\":\"O:34:\\\"Illuminate\\\\Mail\\\\SendQueuedMailable\\\":17:{s:8:\\\"mailable\\\";O:21:\\\"App\\\\Mail\\\\JobAlertMail\\\":23:{s:6:\\\"locale\\\";N;s:4:\\\"from\\\";a:0:{}s:2:\\\"to\\\";a:1:{i:0;a:2:{s:4:\\\"name\\\";N;s:7:\\\"address\\\";s:16:\\\"test@example.com\\\";}}s:2:\\\"cc\\\";a:0:{}s:3:\\\"bcc\\\";a:0:{}s:7:\\\"replyTo\\\";a:0:{}s:7:\\\"subject\\\";N;s:8:\\\"markdown\\\";N;s:7:\\\"\\u0000*\\u0000html\\\";N;s:4:\\\"view\\\";N;s:8:\\\"textView\\\";N;s:8:\\\"viewData\\\";a:0:{}s:11:\\\"attachments\\\";a:0:{}s:14:\\\"rawAttachments\\\";a:0:{}s:15:\\\"diskAttachments\\\";a:0:{}s:7:\\\"\\u0000*\\u0000tags\\\";a:0:{}s:11:\\\"\\u0000*\\u0000metadata\\\";a:0:{}s:9:\\\"callbacks\\\";a:0:{}s:5:\\\"theme\\\";N;s:6:\\\"mailer\\\";s:4:\\\"smtp\\\";s:29:\\\"\\u0000*\\u0000assertionableRenderStrings\\\";N;s:4:\\\"jobs\\\";O:29:\\\"Illuminate\\\\Support\\\\Collection\\\":2:{s:8:\\\"\\u0000*\\u0000items\\\";a:1:{i:0;O:19:\\\"App\\\\Models\\\\Job_post\\\":33:{s:13:\\\"\\u0000*\\u0000connection\\\";s:5:\\\"mysql\\\";s:8:\\\"\\u0000*\\u0000table\\\";s:9:\\\"job_posts\\\";s:13:\\\"\\u0000*\\u0000primaryKey\\\";s:2:\\\"id\\\";s:10:\\\"\\u0000*\\u0000keyType\\\";s:3:\\\"int\\\";s:12:\\\"incrementing\\\";b:1;s:7:\\\"\\u0000*\\u0000with\\\";a:0:{}s:12:\\\"\\u0000*\\u0000withCount\\\";a:0:{}s:19:\\\"preventsLazyLoading\\\";b:0;s:10:\\\"\\u0000*\\u0000perPage\\\";i:15;s:6:\\\"exists\\\";b:1;s:18:\\\"wasRecentlyCreated\\\";b:1;s:28:\\\"\\u0000*\\u0000escapeWhenCastingToString\\\";b:0;s:13:\\\"\\u0000*\\u0000attributes\\\";a:16:{s:5:\\\"title\\\";s:49:\\\"Web Engineer at LemFi (Formerly Lemonade Finance)\\\";s:12:\\\"company_name\\\";s:5:\\\"LemFi\\\";s:12:\\\"company_logo\\\";s:58:\\\"storage\\/logos\\/JmfKhxR1OdArlXF5muDwStEeqBbCU7YD75ce5XbD.png\\\";s:11:\\\"category_id\\\";s:1:\\\"4\\\";s:8:\\\"job_type\\\";s:9:\\\"full-time\\\";s:8:\\\"location\\\";s:14:\\\"Lagos, Nigeria\\\";s:9:\\\"apply_url\\\";s:65:\\\"https:\\/\\/www.myjobmag.com\\/job\\/web-engineer-lemonade-finance-yc-s21\\\";s:17:\\\"short_description\\\";s:3191:\\\"<p><strong>The Role<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>You will be a full-stack engineer with main focus on Frontend working on LemFi&rsquo;s operational &quot;brain&quot;, designing the internal software that automates our most critical financial processes. Your mission is to transform complex, high-volume back-office tasks like payments operations, fraud investigations, and regulatory reporting into streamlined, front-end functionality.<\\/li>\\r\\n\\t<li>You won&rsquo;t just be building tools; you&rsquo;ll create efficient internal interfaces that empower our operations teams to move faster and with greater precision. By embedding AI and agentic automation into every workflow, you&rsquo;ll ensure that managing global money movement is as intelligent and effortless as the user experience it supports.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>How You&#39;ll Contribute<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Build &amp; Ship: Design and deliver high-quality, scalable web features using Vue.js, with a strong focus on efficiency, security, and maintainability.<\\/li>\\r\\n\\t<li>Own the Experience: Take end-to-end responsibility for features from technical design and implementation to testing, deployment, and production support.<\\/li>\\r\\n\\t<li>BFF Development: Implement and maintain backend-for-frontend logic in TypeScript, shaping APIs and data models that serve the needs of the web client efficiently and securely.<\\/li>\\r\\n\\t<li>Ensure Reliability: Uphold high engineering standards through automated testing, clean code practices, and proactive monitoring of frontend and BFF services.<\\/li>\\r\\n\\t<li>Drive Cross-Functional Impact: Collaborate closely with Product, Design, and Backend teams to deliver compliant, customer-centric financial experiences aligned with regulatory requirements.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>Who You Are<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Impact-Driven: You focus on delivering meaningful user and business outcomes, not just shipping features.<\\/li>\\r\\n\\t<li>Technically Grounded: You have strong experience building business-oriented web applications and are comfortable working with TypeScript on the backend for BFF logic.<\\/li>\\r\\n\\t<li>High Ownership: You take responsibility for your work from concept through production and continuously look for ways to improve what you&rsquo;ve built.<\\/li>\\r\\n\\t<li>Collaborative: You communicate clearly with Product, Design, and Engineering, valuing shared success over individual credit.<\\/li>\\r\\n\\t<li>Curious: You actively seek feedback and stay up to date with modern frontend patterns, AI tooling, and best practices.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>What You&#39;ll Bring<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Experience building production web apps with Vue.js &amp; Nuxt.js<\\/li>\\r\\n\\t<li>Strong TypeScript skills, including BFF development<\\/li>\\r\\n\\t<li>Proficient in JavaScript, HTML, CSS, SASS<\\/li>\\r\\n\\t<li>Experience working with and shaping REST APIs<\\/li>\\r\\n\\t<li>Solid understanding of modern frontend architecture, state management &amp; performance optimisation<\\/li>\\r\\n\\t<li>Familiar with Git, testing frameworks (Jest\\/Mocha), build tools &amp; CI\\/CD<\\/li>\\r\\n\\t<li>Working knowledge of cloud environments &amp; Docker<\\/li>\\r\\n\\t<li>Hands-on experience using LLMs for coding and daily workflows<\\/li>\\r\\n<\\/ul>\\\";s:8:\\\"deadline\\\";N;s:6:\\\"status\\\";s:6:\\\"active\\\";s:16:\\\"experience_level\\\";s:3:\\\"mid\\\";s:12:\\\"salary_range\\\";N;s:6:\\\"source\\\";s:8:\\\"MyJobMag\\\";s:10:\\\"updated_at\\\";s:19:\\\"2026-02-11 19:09:22\\\";s:10:\\\"created_at\\\";s:19:\\\"2026-02-11 19:09:22\\\";s:2:\\\"id\\\";i:11;}s:11:\\\"\\u0000*\\u0000original\\\";a:16:{s:5:\\\"title\\\";s:49:\\\"Web Engineer at LemFi (Formerly Lemonade Finance)\\\";s:12:\\\"company_name\\\";s:5:\\\"LemFi\\\";s:12:\\\"company_logo\\\";s:58:\\\"storage\\/logos\\/JmfKhxR1OdArlXF5muDwStEeqBbCU7YD75ce5XbD.png\\\";s:11:\\\"category_id\\\";s:1:\\\"4\\\";s:8:\\\"job_type\\\";s:9:\\\"full-time\\\";s:8:\\\"location\\\";s:14:\\\"Lagos, Nigeria\\\";s:9:\\\"apply_url\\\";s:65:\\\"https:\\/\\/www.myjobmag.com\\/job\\/web-engineer-lemonade-finance-yc-s21\\\";s:17:\\\"short_description\\\";s:3191:\\\"<p><strong>The Role<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>You will be a full-stack engineer with main focus on Frontend working on LemFi&rsquo;s operational &quot;brain&quot;, designing the internal software that automates our most critical financial processes. Your mission is to transform complex, high-volume back-office tasks like payments operations, fraud investigations, and regulatory reporting into streamlined, front-end functionality.<\\/li>\\r\\n\\t<li>You won&rsquo;t just be building tools; you&rsquo;ll create efficient internal interfaces that empower our operations teams to move faster and with greater precision. By embedding AI and agentic automation into every workflow, you&rsquo;ll ensure that managing global money movement is as intelligent and effortless as the user experience it supports.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>How You&#39;ll Contribute<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Build &amp; Ship: Design and deliver high-quality, scalable web features using Vue.js, with a strong focus on efficiency, security, and maintainability.<\\/li>\\r\\n\\t<li>Own the Experience: Take end-to-end responsibility for features from technical design and implementation to testing, deployment, and production support.<\\/li>\\r\\n\\t<li>BFF Development: Implement and maintain backend-for-frontend logic in TypeScript, shaping APIs and data models that serve the needs of the web client efficiently and securely.<\\/li>\\r\\n\\t<li>Ensure Reliability: Uphold high engineering standards through automated testing, clean code practices, and proactive monitoring of frontend and BFF services.<\\/li>\\r\\n\\t<li>Drive Cross-Functional Impact: Collaborate closely with Product, Design, and Backend teams to deliver compliant, customer-centric financial experiences aligned with regulatory requirements.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>Who You Are<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Impact-Driven: You focus on delivering meaningful user and business outcomes, not just shipping features.<\\/li>\\r\\n\\t<li>Technically Grounded: You have strong experience building business-oriented web applications and are comfortable working with TypeScript on the backend for BFF logic.<\\/li>\\r\\n\\t<li>High Ownership: You take responsibility for your work from concept through production and continuously look for ways to improve what you&rsquo;ve built.<\\/li>\\r\\n\\t<li>Collaborative: You communicate clearly with Product, Design, and Engineering, valuing shared success over individual credit.<\\/li>\\r\\n\\t<li>Curious: You actively seek feedback and stay up to date with modern frontend patterns, AI tooling, and best practices.<\\/li>\\r\\n<\\/ul>\\r\\n\\r\\n<p><strong>What You&#39;ll Bring<\\/strong><\\/p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>Experience building production web apps with Vue.js &amp; Nuxt.js<\\/li>\\r\\n\\t<li>Strong TypeScript skills, including BFF development<\\/li>\\r\\n\\t<li>Proficient in JavaScript, HTML, CSS, SASS<\\/li>\\r\\n\\t<li>Experience working with and shaping REST APIs<\\/li>\\r\\n\\t<li>Solid understanding of modern frontend architecture, state management &amp; performance optimisation<\\/li>\\r\\n\\t<li>Familiar with Git, testing frameworks (Jest\\/Mocha), build tools &amp; CI\\/CD<\\/li>\\r\\n\\t<li>Working knowledge of cloud environments &amp; Docker<\\/li>\\r\\n\\t<li>Hands-on experience using LLMs for coding and daily workflows<\\/li>\\r\\n<\\/ul>\\\";s:8:\\\"deadline\\\";N;s:6:\\\"status\\\";s:6:\\\"active\\\";s:16:\\\"experience_level\\\";s:3:\\\"mid\\\";s:12:\\\"salary_range\\\";N;s:6:\\\"source\\\";s:8:\\\"MyJobMag\\\";s:10:\\\"updated_at\\\";s:19:\\\"2026-02-11 19:09:22\\\";s:10:\\\"created_at\\\";s:19:\\\"2026-02-11 19:09:22\\\";s:2:\\\"id\\\";i:11;}s:10:\\\"\\u0000*\\u0000changes\\\";a:0:{}s:11:\\\"\\u0000*\\u0000previous\\\";a:0:{}s:8:\\\"\\u0000*\\u0000casts\\\";a:3:{s:11:\\\"is_featured\\\";s:7:\\\"boolean\\\";s:8:\\\"deadline\\\";s:8:\\\"datetime\\\";s:9:\\\"is_remote\\\";s:7:\\\"boolean\\\";}s:17:\\\"\\u0000*\\u0000classCastCache\\\";a:0:{}s:21:\\\"\\u0000*\\u0000attributeCastCache\\\";a:0:{}s:13:\\\"\\u0000*\\u0000dateFormat\\\";N;s:10:\\\"\\u0000*\\u0000appends\\\";a:0:{}s:19:\\\"\\u0000*\\u0000dispatchesEvents\\\";a:0:{}s:14:\\\"\\u0000*\\u0000observables\\\";a:0:{}s:12:\\\"\\u0000*\\u0000relations\\\";a:0:{}s:10:\\\"\\u0000*\\u0000touches\\\";a:0:{}s:27:\\\"\\u0000*\\u0000relationAutoloadCallback\\\";N;s:26:\\\"\\u0000*\\u0000relationAutoloadContext\\\";N;s:10:\\\"timestamps\\\";b:1;s:13:\\\"usesUniqueIds\\\";b:0;s:9:\\\"\\u0000*\\u0000hidden\\\";a:0:{}s:10:\\\"\\u0000*\\u0000visible\\\";a:0:{}s:11:\\\"\\u0000*\\u0000fillable\\\";a:15:{i:0;s:5:\\\"title\\\";i:1;s:12:\\\"company_name\\\";i:2;s:12:\\\"company_logo\\\";i:3;s:11:\\\"category_id\\\";i:4;s:8:\\\"job_type\\\";i:5;s:8:\\\"location\\\";i:6;s:16:\\\"experience_level\\\";i:7;s:12:\\\"salary_range\\\";i:8;s:17:\\\"short_description\\\";i:9;s:9:\\\"apply_url\\\";i:10;s:8:\\\"deadline\\\";i:11;s:11:\\\"is_featured\\\";i:12;s:6:\\\"status\\\";i:13;s:6:\\\"source\\\";i:14;s:9:\\\"is_remote\\\";}s:10:\\\"\\u0000*\\u0000guarded\\\";a:1:{i:0;s:1:\\\"*\\\";}}}s:28:\\\"\\u0000*\\u0000escapeWhenCastingToString\\\