--
-- Table structure for table `job_posts`
--

CREATE TABLE `job_posts` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `uuid` char(36) NOT NULL,
  `title` varchar(255) NOT NULL,
  `company_name` varchar(255) NOT NULL,
  `is_verified` tinyint(1) NOT NULL DEFAULT 0,
  `about_company` text DEFAULT NULL,
  `company_logo` varchar(255) DEFAULT NULL,
  `category_id` bigint(20) UNSIGNED NOT NULL,
  `job_type` enum('full-time','part-time','contract','internship','temporary') NOT NULL,
  `location` varchar(255) NOT NULL,
  `experience_level` enum('entry','mid','senior') DEFAULT NULL,
  `salary_range` varchar(255) DEFAULT NULL,
  `short_description` text NOT NULL,
  `apply_url` varchar(255) NOT NULL,
  `deadline` date DEFAULT NULL,
  `is_featured` tinyint(1) NOT NULL DEFAULT 0,
  `featured_until` timestamp NULL DEFAULT NULL,
  `status` enum('active','expired','pending','inactive','rejected') NOT NULL DEFAULT 'active',
  `source` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_remote` tinyint(1) NOT NULL DEFAULT 0,
  `slug` varchar(255) NOT NULL,
  `is_paid` tinyint(1) NOT NULL DEFAULT 0,
  `payment_reference` varchar(255) DEFAULT NULL,
  `paid_at` timestamp NULL DEFAULT NULL,
  `is_approved` tinyint(1) NOT NULL DEFAULT 0,
  `user_id` bigint(20) UNSIGNED NOT NULL,
  `amount_paid` decimal(10,2) DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `job_posts`
--

INSERT INTO `job_posts` (`id`, `uuid`, `title`, `company_name`, `is_verified`, `about_company`, `company_logo`, `category_id`, `job_type`, `location`, `experience_level`, `salary_range`, `short_description`, `apply_url`, `deadline`, `is_featured`, `featured_until`, `status`, `source`, `created_at`, `updated_at`, `is_remote`, `slug`, `is_paid`, `payment_reference`, `paid_at`, `is_approved`, `user_id`, `amount_paid`, `deleted_at`) VALUES
(1, 'fbed7933-2524-4aec-8276-5afdcae347e9', 'Customer Success Associate (Abuja)', 'Reliance Health', 1, NULL, NULL, 6, 'full-time', 'Abuja, Nigeria', 'senior', '200', '<p>Reliance Health&rsquo;s mission is to make quality healthcare delightful, affordable, and accessible in emerging markets. From Nigeria, Egypt, Senegal and beyond, we offer comprehensive health plans tailored to both employers&rsquo; and employees&rsquo; needs through an integrated approach that includes telemedicine, affordable health insurance, and a combination of partner and proprietary healthcare facilities. By leveraging advanced technology, we are transforming the healthcare landscape, making it more efficient and accessible for everyone.</p>\r\n\r\n<p>We are seeking a&nbsp;<strong>Customer Success Associate&nbsp;</strong>to join our Abuja team. You will be part of the frontline team responsible for delivering high-quality support and ensuring customers have a seamless experience across all channels. The role involves managing customer interactions, analyzing feedback, and supporting initiatives that improve satisfaction and retention. It is ideal for someone detail-oriented, customer-focused, and eager to grow within customer success.</p>\r\n\r\n<p>As a Customer Success Associate, you will do the following:</p>\r\n\r\n<ul>\r\n	<li>Assist in managing customer relationships using CRM systems, ensuring accurate records of interactions and preferences, while tracking engagement, monitoring satisfaction, and identifying retention opportunities.</li>\r\n	<li>Collect and analyze customer feedback through surveys, interviews, and other channels, summarizing trends and insights to support decision-making and enhance retention strategies.</li>\r\n	<li>Support customer communication by drafting emails, letters, and other correspondence for inquiries, concerns, or follow-ups, and assist in creating targeted campaigns to drive engagement and loyalty.</li>\r\n	<li>Apply basic selling and negotiation skills when engaging with corporate clients, addressing their needs, negotiating renewals, and supporting upsell opportunities.</li>\r\n	<li>Contribute to the development and implementation of customer retention strategies, collaborating with cross-functional teams to reduce churn and improve customer lifetime value.</li>\r\n</ul>\r\n\r\n<p><strong>Requirements</strong></p>\r\n\r\n<ul>\r\n	<li>Bachelor&rsquo;s degree in Business, Communications, or related field.</li>\r\n	<li>1&ndash;2 years&rsquo; experience in customer success, account management, or a client-facing role.</li>\r\n	<li>Familiarity with CRM tools and basic data analysis.</li>\r\n	<li>Strong written and verbal communication skills.</li>\r\n	<li>Ability to build rapport, manage multiple customer interactions, and resolve concerns.</li>\r\n	<li>Negotiation and problem-solving skills with a customer-first mindset.</li>\r\n	<li>Based in Abuja with flexibility to work in a hybrid setup.</li>\r\n</ul>\r\n\r\n<p><strong>Benefits</strong></p>\r\n\r\n<p>At Reliance Health, we prioritize our people and their well-being. Our benefits package is designed to support your success, growth, and happiness. Here&rsquo;s what you&rsquo;ll enjoy:</p>\r\n\r\n<ul>\r\n	<li><strong>Remote-First Environment</strong><br />\r\n	Work from anywhere while staying connected to a vibrant, collaborative team.</li>\r\n	<li><strong>Competitive Salary and Benefits</strong><br />\r\n	We offer a salary that&rsquo;s benchmarked against the best in the industry, ensuring your expertise and impact are fully rewarded.</li>\r\n	<li><strong>Premium Health Insurance</strong><br />\r\n	Comprehensive health coverage for you and your family, because your well-being comes first.</li>\r\n	<li><strong>Unlimited Leave</strong><br />\r\n	Take the time you need when you need it&mdash;no limits, no questions.</li>\r\n	<li><strong>Meaningful Impact</strong><br />\r\n	Play a key role in transforming customer experiences and shaping healthcare innovation.</li>\r\n	<li><strong>Collaborative Work Culture</strong><br />\r\n	Join a supportive, inclusive, and team-focused environment that celebrates diversity.</li>\r\n	<li><strong>Growth Opportunities</strong><br />\r\n	Access tools, mentorship, and resources to elevate your skills and career.</li>\r\n	<li><strong>Learning &amp; Development Allowance</strong><br />\r\n	We provide an allowance to support your ongoing professional growth and skill enhancement.</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>This is more than a job it&#39;s a chance to grow, thrive, and make a real difference. At Reliance Health, your journey matters.</strong></p>', 'https://ng.indeed.com/viewjob?jk=f2e76a2426407bfc&from=shareddesktop_copy', '2026-02-20', 0, NULL, 'active', 'Indeed', '2026-01-29 20:28:54', '2026-02-16 07:49:23', 0, 'customer-success-associate-abuja', 1, NULL, NULL, 1, 1, NULL, NULL),
(3, 'ae9dc3b1-dc32-4326-bd04-6321a629eca1', 'Test Laravel Dev', 'AntApple', 0, NULL, NULL, 1, 'full-time', 'Abuja, Nigeria', 'mid', NULL, 'Testing alert', 'https://example.com', NULL, 0, NULL, 'active', NULL, '2026-02-09 06:34:43', '2026-02-16 07:49:23', 0, 'test-laravel-dev', 1, NULL, NULL, 1, 1, NULL, NULL),
