  `billing_cycle` enum('monthly','yearly') NOT NULL,
  `job_limit` int(11) NOT NULL DEFAULT 1,
  `featured_limit` int(11) NOT NULL DEFAULT 0,
  `feature_duration` int(11) NOT NULL DEFAULT 0,
  `can_view_applicants` tinyint(1) NOT NULL DEFAULT 1,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
