--
-- Dumping data for table `plans`
--

INSERT INTO `plans` (`id`, `name`, `slug`, `price`, `billing_cycle`, `job_limit`, `featured_limit`, `feature_duration`, `can_view_applicants`, `is_active`, `description`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Starter Tier', 'starter-tier', 10000.00, 'monthly', 5, 0, 0, 1, 1, '<p>This affordable tier allows companies to begin hiring with essential job posting features and candidate access. It&rsquo;s ideal for small businesses, startups, or occasional hiring needs.</p>\r\n\r\n<p><strong>Includes:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Limited active job postings (5)</p>\r\n	</li>\r\n	<li>\r\n	<p>Standard listing visibility</p>\r\n	</li>\r\n	<li>\r\n	<p>Basic applicant dashboard</p>\r\n	</li>\r\n	<li>\r\n	<p>Email alerts for new applicants</p>\r\n	</li>\r\n	<li>\r\n	<p>Standard company profile display</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Best for:</strong><br />\r\nSmall businesses, occasional hiring, early-stage teams.</p>', '2026-02-20 14:42:08', '2026-02-28 21:11:04', NULL),
(2, 'Growth Tier', 'growth-tier', 25000.00, 'monthly', 10, 2, 7, 1, 1, '<p>This tier gives you more job slots and advanced visibility to help scale your recruiting efforts. You can post multiple jobs while benefiting from priority exposure and stronger applicant engagement tools.</p>\r\n\r\n<p><strong>Includes all Basic features, plus:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>More active job postings (10)</p>\r\n	</li>\r\n	<li>\r\n	<p>Featured job placement</p>\r\n	</li>\r\n	<li>\r\n	<p>Priority in search results</p>\r\n	</li>\r\n	<li>\r\n	<p>Advanced applicant filtering</p>\r\n	</li>\r\n	<li>\r\n	<p>Enhanced company profile &amp; analytics</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Best for:</strong><br />\r\nGrowing companies that hire consistently and want to attract more qualified candidates.</p>', '2026-02-28 21:15:20', '2026-02-28 21:15:20', NULL),
(3, 'Enterprise Tier', 'enterprise-tier', 50000.00, 'monthly', 25, 5, 30, 1, 1, '<p>Designed for enterprises or agencies hiring at scale, this plan offers the most job postings and top-tier recruitment features, including branding and priority placement that elevates your company above the competition.</p>\r\n\r\n<p><strong>Includes all Standard features, plus:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Highest active job posting limit (30)</p>\r\n	</li>\r\n	<li>\r\n	<p>Premium featured placement on homepage &amp; categories</p>\r\n	</li>\r\n	<li>\r\n	<p>Unlimited applicant views</p>\r\n	</li>\r\n	<li>\r\n	<p>Employer branding spotlight</p>\r\n	</li>\r\n	<li>\r\n	<p>Priority support</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Best for:</strong><br />\r\nLarge enterprises, recruitment agencies, high-growth companies with continuous hiring demand.</p>', '2026-02-28 21:20:05', '2026-02-28 21:20:05', NULL);

